:root {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  color-scheme: light dark;
  color: #1a1a1a;
  background: #f7f7f7;
}

body {
  margin: 0;
  min-height: 100vh;
}

.app {
  max-width: 960px;
  margin: 0 auto;
  padding: 2rem 1.5rem;
}

.header {
  display: flex;
  align-items: baseline;
  gap: 1rem;
  margin-bottom: 1.5rem;
}

.header h1 {
  font-size: 1.5rem;
  margin: 0;
}

.header .date {
  color: #666;
  font-size: 0.9rem;
}

.tabs {
  display: flex;
  gap: 0.25rem;
  border-bottom: 1px solid #ddd;
  margin-bottom: 1.5rem;
}

.tab {
  padding: 0.5rem 1rem;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  cursor: pointer;
  font-size: 0.95rem;
  color: #555;
}

.tab.active {
  border-bottom-color: #1a1a1a;
  color: #1a1a1a;
  font-weight: 600;
}

.tab:disabled {
  color: #bbb;
  cursor: default;
}

.badge {
  display: inline-block;
  padding: 0.25rem 0.75rem;
  border-radius: 999px;
  font-weight: 600;
  font-size: 0.85rem;
  letter-spacing: 0.05em;
  color: #fff;
}

.badge.pass { background: #2e7d32; }
.badge.watch { background: #ed8c00; }
.badge.skip { background: #c62828; }
.badge.unknown { background: #757575; }

.card {
  background: #fff;
  border: 1px solid #e5e5e5;
  border-radius: 8px;
  padding: 1.25rem 1.5rem;
}

.card h2 {
  margin: 0 0 1rem 0;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 1.1rem;
}

.rationale {
  margin-top: 1rem;
  color: #444;
  line-height: 1.5;
}

.ratios {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
  gap: 0.75rem;
  margin-top: 1rem;
}

.ratio {
  background: #fafafa;
  border: 1px solid #eee;
  border-radius: 6px;
  padding: 0.5rem 0.75rem;
}

.ratio .label {
  color: #777;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.ratio .value {
  font-size: 1.1rem;
  font-weight: 600;
  margin-top: 0.25rem;
}

.empty {
  color: #888;
  font-style: italic;
}

.picker {
  margin-left: auto;
  padding: 0.35rem 0.5rem;
  font-size: 0.9rem;
}

.model-header {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 0.75rem;
  margin-top: 1rem;
}

.model-header-cell {
  background: #fafafa;
  border: 1px solid #eee;
  border-radius: 6px;
  padding: 0.5rem 0.75rem;
}

.model-header-cell .label {
  color: #777;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.model-header-cell .value {
  font-size: 0.95rem;
  font-weight: 600;
  margin-top: 0.25rem;
  word-break: break-word;
}

.iv-range {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 0.5rem;
  margin-top: 1.25rem;
}

.iv-cell {
  background: #fafafa;
  border: 1px solid #e5e5e5;
  border-radius: 6px;
  padding: 0.6rem 0.75rem;
  text-align: center;
}

.iv-cell .label {
  color: #777;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.iv-cell .value {
  font-size: 1.15rem;
  font-weight: 600;
  margin-top: 0.25rem;
}

.iv-cell-current {
  border-color: #1a1a1a;
  background: #fff;
}

.iv-cell-current .label {
  color: #1a1a1a;
}

.position-sizing {
  margin-top: 1.25rem;
  padding-top: 1rem;
  border-top: 1px solid #eee;
}

.position-sizing-line {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  flex-wrap: wrap;
}

.position-sizing-line .label {
  color: #777;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.position-sizing-line .band {
  font-weight: 600;
  font-size: 1rem;
}

.pre-profit-note {
  margin-top: 1rem;
  font-size: 0.85rem;
}

import { useMemo, useState } from 'react';
import { loadReports } from './lib/reports.js';
import ScreenReport from './components/ScreenReport.jsx';
import ModelReport from './components/ModelReport.jsx';

const TABS = ['Screen', 'Signal', 'Model', 'Timing', 'Summary'];

export default function App() {
  const reports = useMemo(() => loadReports(), []);
  const [selectedPath, setSelectedPath] = useState(reports[0]?.path ?? null);
  const [tab, setTab] = useState('Screen');

  const current = reports.find((r) => r.path === selectedPath) ?? reports[0];

  if (!current) {
    return (
      <div className="app">
        <h1>Equity Research</h1>
        <p className="empty">No reports found in <code>reports/</code>.</p>
      </div>
    );
  }

  const { data } = current;
  const stages = data.stages ?? {};

  return (
    <div className="app">
      <div className="header">
        <h1>{data.ticker}{data.company ? ` — ${data.company}` : ''}</h1>
        <span className="date">{data.date}</span>
        <select
          className="picker"
          name="report"
          aria-label="Select report"
          value={current.path}
          onChange={(e) => setSelectedPath(e.target.value)}
        >
          {reports.map((r) => (
            <option key={r.path} value={r.path}>
              {r.ticker} — {r.dateStr}
            </option>
          ))}
        </select>
      </div>

      <div className="tabs">
        {TABS.map((name) => {
          const key = name.toLowerCase();
          const hasData = key === 'summary' ? true : Boolean(stages[key]);
          return (
            <button
              key={name}
              className={`tab ${tab === name ? 'active' : ''}`}
              onClick={() => setTab(name)}
              disabled={!hasData}
            >
              {name}
            </button>
          );
        })}
      </div>

      {tab === 'Screen' && <ScreenReport stage={stages.screen} />}
      {tab === 'Model' && <ModelReport stage={stages.model} />}
      {tab !== 'Screen' && tab !== 'Model' && (
        <p className="empty">{tab} view not yet implemented.</p>
      )}
    </div>
  );
}

import {
  verdictClass,
  formatCurrency,
  formatPercent,
  formatBillions
} from '../lib/formatters.js';

const PRE_PROFIT_NOTE = 'Visual breakdown is ESTABLISHED-only for v1.';

function HeaderCell({ label, value }) {
  return (
    <div className="model-header-cell">
      <div className="label">{label}</div>
      <div className="value">{value}</div>
    </div>
  );
}

function IvCell({ label, value, accent }) {
  return (
    <div className={`iv-cell${accent ? ` iv-cell-${accent}` : ''}`}>
      <div className="label">{label}</div>
      <div className="value">{formatCurrency(value)}</div>
    </div>
  );
}

export default function ModelReport({ stage }) {
  if (!stage) {
    return <p className="empty">No model data in this report.</p>;
  }

  const {
    method,
    profit_stage,
    base_wacc,
    ntm_revenue,
    fcf_margin_ttm,
    current_price,
    intrinsic_value_range = {},
    range_vs_price,
    position_sizing = {}
  } = stage;

  const isPreProfit = typeof method === 'string' && method.startsWith('pre-profit');
  const rangeClass = `badge ${verdictClass(range_vs_price)}`;
  const signalVerdict = position_sizing.signal_verdict;
  const signalClass = signalVerdict ? `badge ${verdictClass(signalVerdict)}` : null;

  return (
    <div className="card">
      <h2>
        Model
        {range_vs_price && <span className={rangeClass}>{range_vs_price}</span>}
        {profit_stage && (
          <span style={{ color: '#777', fontWeight: 400, fontSize: '0.85rem' }}>
            {profit_stage}
          </span>
        )}
      </h2>

      <div className="model-header">
        <HeaderCell label="Method" value={method ?? '—'} />
        <HeaderCell label="Base WACC" value={formatPercent(base_wacc)} />
        <HeaderCell label="NTM Revenue" value={formatBillions(ntm_revenue)} />
        <HeaderCell label="Clean FCF Margin TTM" value={formatPercent(fcf_margin_ttm)} />
      </div>

      <div className="iv-range">
        <IvCell label="Bear" value={intrinsic_value_range.bear} accent="bear" />
        <IvCell label="Base" value={intrinsic_value_range.base} accent="base" />
        <IvCell label="Bull" value={intrinsic_value_range.bull} accent="bull" />
        <IvCell label="Current" value={current_price} accent="current" />
      </div>

      {position_sizing.band && (
        <div className="position-sizing">
          <div className="position-sizing-line">
            <span className="label">Position sizing</span>
            <span className="band">{position_sizing.band}</span>
            {signalVerdict && <span className={signalClass}>{signalVerdict}</span>}
          </div>
          {position_sizing.rationale && (
            <p className="rationale">{position_sizing.rationale}</p>
          )}
        </div>
      )}

      {isPreProfit && <p className="empty pre-profit-note">{PRE_PROFIT_NOTE}</p>}
    </div>
  );
}

export function verdictClass(verdict) {
  switch ((verdict || '').toUpperCase()) {
    case 'PASS':
    case 'BUY':
    case 'ACT NOW':
    case 'MARGIN OF SAFETY':
    case 'WITHIN BEAR-BASE':
      return 'pass';
    case 'WATCH':
    case 'CONDITIONAL':
    case 'WAIT FOR CATALYST':
    case 'WITHIN BASE-BULL':
      return 'watch';
    case 'SKIP':
    case 'CAUTION':
    case 'WAIT FOR BETTER ENTRY':
    case 'ABOVE BULL':
      return 'skip';
    default:
      return 'unknown';
  }
}

const RATIO_LABELS = {
  pe_ratio: 'P/E',
  ps_ratio: 'P/S',
  ev_ebitda: 'EV/EBITDA',
  pfcf: 'P/FCF',
  ev_revenue: 'EV/Revenue'
};

export function ratioLabel(key) {
  return RATIO_LABELS[key] ?? key;
}

export function formatRatio(value) {
  if (value == null || Number.isNaN(value)) return '—';
  return Number(value).toFixed(1);
}

function isNum(value) {
  return value != null && !Number.isNaN(Number(value));
}

export function formatCurrency(value) {
  if (!isNum(value)) return '—';
  const n = Number(value);
  if (Math.abs(n) >= 1000) return `$${n.toFixed(0)}`;
  return `$${n.toFixed(2)}`;
}

export function formatPercent(value, digits = 1) {
  if (!isNum(value)) return '—';
  return `${(Number(value) * 100).toFixed(digits)}%`;
}

export function formatBillions(value) {
  if (!isNum(value)) return '—';
  const billions = Number(value) / 1e9;
  if (Math.abs(billions) >= 100) return `$${billions.toFixed(0)}B`;
  return `$${billions.toFixed(1)}B`;
}

export function formatPerShare(value) {
  if (!isNum(value)) return '—';
  return `$${Number(value).toFixed(2)}/sh`;
}

